// Dedup: o ERP pode trazer mais de uma linha pro mesmo filial+pedido+item
// (ex.: entrega parcial do mesmo item, ou fan-out de join). Mantém só uma
// linha por chave, priorizando o estagio mais atrasado (mesma logica do
// dashboard, que usa o flag_estagio minimo como "gargalo" do pedido), pra
// nao duplicar a chave dentro do mesmo INSERT (Postgres nao deixa o
// ON CONFLICT DO UPDATE afetar a mesma linha 2x).
const porChave = new Map();
for (const it of items) {
  const j = it.json;
  const chave = `${j.filial}|${j.pedido}|${j.item}`;
  const atual = porChave.get(chave);
  if (!atual || Number(j.flag_estagio) < Number(atual.json.flag_estagio)) {
    porChave.set(chave, it);
  }
}
const itemsDedup = Array.from(porChave.values());

const CHUNK_SIZE = 300;
const out = [];

for (let i = 0; i < itemsDedup.length; i += CHUNK_SIZE) {
  const chunk = itemsDedup.slice(i, i + CHUNK_SIZE);
  const rows = chunk.map(item => {
    const j = item.json;
    return `(${esc(j.filial)}, ${esc(j.pedido)}, ${esc(j.data_emissao)}, ${esc(j.nome_vendedor)}, ${esc(j.nome_cliente)}, ${escNum(j.valor_pedido)}, ${esc(j.item)}, ${esc(j.descricao)}, ${escNum(j.flag_estagio)}, ${escNum(j.qtd_pedida)}, ${escNum(j.qtd_faturada)}, ${escNum(j.qtd_entregue)}, ${escNum(j.valor_unitario)}, ${escNum(j.percentual_desconto)}, ${escNum(j.valor_desconto)}, ${escNum(j.valor_custo)}, ${escNum(j.valor_bruto_item)}, ${escNum(j.valor_final_item)}, ${esc(j.desc_estagio)}, ${esc(j.data_hora_inclusao)}, ${esc(j.status_resumo_erp)}, ${esc(j.atualizado_em)})`;
  }).join(',\n');

  const sql = `INSERT INTO pd_item_estagio (
  filial, pedido, data_emissao, nome_vendedor, nome_cliente, valor_pedido, item, descricao,
  flag_estagio, qtd_pedida, qtd_faturada, qtd_entregue, valor_unitario, percentual_desconto,
  valor_desconto, valor_custo, valor_bruto_item, valor_final_item, desc_estagio,
  data_hora_inclusao, status_resumo_erp, atualizado_em
) VALUES
${rows}
ON CONFLICT (filial, pedido, item) DO UPDATE SET
  data_emissao = EXCLUDED.data_emissao,
  nome_vendedor = EXCLUDED.nome_vendedor,
  nome_cliente = EXCLUDED.nome_cliente,
  valor_pedido = EXCLUDED.valor_pedido,
  descricao = EXCLUDED.descricao,
  flag_estagio = EXCLUDED.flag_estagio,
  qtd_pedida = EXCLUDED.qtd_pedida,
  qtd_faturada = EXCLUDED.qtd_faturada,
  qtd_entregue = EXCLUDED.qtd_entregue,
  valor_unitario = EXCLUDED.valor_unitario,
  percentual_desconto = EXCLUDED.percentual_desconto,
  valor_desconto = EXCLUDED.valor_desconto,
  valor_custo = EXCLUDED.valor_custo,
  valor_bruto_item = EXCLUDED.valor_bruto_item,
  valor_final_item = EXCLUDED.valor_final_item,
  desc_estagio = EXCLUDED.desc_estagio,
  data_hora_inclusao = EXCLUDED.data_hora_inclusao,
  status_resumo_erp = EXCLUDED.status_resumo_erp,
  atualizado_em = EXCLUDED.atualizado_em;`;

  out.push({ json: { sql, batch: (i / CHUNK_SIZE) + 1, rows: chunk.length } });
}

return out;

